import{_ as r,C as a,o as i,c as n,E as o,w as s,a as d,a0 as l}from"./chunks/framework.CkNTPv-z.js";const f=JSON.parse('{"title":"Germany Healthcare & HRT","description":"Transgender healthcare access in Germany","frontmatter":{"layout":"doc","title":"Germany Healthcare & HRT","description":"Transgender healthcare access in Germany"},"headers":[],"relativePath":"europe/germany/healthcare.md","filePath":"europe/germany/healthcare.md","lastUpdated":null}'),c={name:"europe/germany/healthcare.md"};function h(p,e,u,m,y,b){const t=a("Badge");return i(),n("div",null,[o(t,{variant:"green"},{default:s(()=>[...e[0]||(e[0]=[d("Informed Consent (Varies by Region)",-1)])]),_:1}),e[1]||(e[1]=l('<h1 id="healthcare-hrt-in-germany" tabindex="-1">Healthcare &amp; HRT in Germany <a class="header-anchor" href="#healthcare-hrt-in-germany" aria-label="Permalink to &quot;Healthcare &amp; HRT in Germany&quot;">​</a></h1><h2 id="access-model" tabindex="-1">Access Model <a class="header-anchor" href="#access-model" aria-label="Permalink to &quot;Access Model&quot;">​</a></h2><p>Germany does not have a single national model — access varies significantly by region and practitioner. Major cities like Berlin, Hamburg, and Cologne have many informed consent providers, while rural areas may require a therapist&#39;s referral letter (Indikationsschreiben). The S3 guideline for transgender healthcare supports informed consent, but implementation is uneven.</p><p>Public health insurance (Krankenkasse) covers HRT, therapy, and surgeries. A therapist&#39;s Indikationsschreiben is often required for insurance to cover HRT, though some endocrinologists prescribe on a self-pay informed consent basis.</p><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th></tr></thead><tbody><tr><td>Medizinische Hochschule Hannover</td><td>Hanover</td><td>Multidisciplinary gender clinic</td></tr><tr><td>Institut für Sexualwissenschaft</td><td>Berlin</td><td>HRT, counselling, surgery referrals</td></tr><tr><td>Praxis Dr. Pottek</td><td>Hamburg</td><td>Endocrinology, HRT</td></tr><tr><td>Queermed Network</td><td>Nationwide</td><td>Directory of trans-friendly providers</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><p>EU/EEA prescriptions are recognised in Germany. Non-EU arrivals need a German prescription. Use the Queermed directory to find trans-competent doctors. A medical history in German or English documenting your HRT is essential.</p><p>A 3-month supply of HRT for personal use is generally permitted with a valid prescription.</p><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><p>Gender-affirming surgeries are covered by public health insurance after approval (Kostenübernahme). Top surgery, bottom surgery, hysterectomy, and facial feminisation are available. Major surgical centres include Munich, Berlin, and Hamburg. Approval wait times are 3-6 months; surgical wait times are 6-18 months.</p><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Public Cost</th><th>Private Cost</th></tr></thead><tbody><tr><td>GP visit</td><td>Free (public)</td><td>€50-100</td></tr><tr><td>Endocrinologist</td><td>Free (public)</td><td>€80-150</td></tr><tr><td>HRT (monthly)</td><td>€10-30</td><td>€40-80</td></tr><tr><td>Top Surgery</td><td>Covered (public)</td><td>€5,000-10,000</td></tr><tr><td>Bottom Surgery</td><td>Covered (public)</td><td>€15,000-30,000</td></tr></tbody></table>',13))])}const v=r(c,[["render",h]]);export{f as __pageData,v as default};
